import pandas as pd
import matplotlib.pyplot as plt

def task_func(df, dct, columns=None, plot_histograms=False):
    if not isinstance(df, pd.DataFrame):
        raise ValueError("Input df must be a DataFrame")

    # Replace values in the dataframe using the provided dictionary
    for col, val in dct.items():
        df[col] = df[col].replace(dct)

    # Create an empty list to store histogram figures
    figs = []

    # If plot_histograms is True and columns are specified, create histograms for those columns
    if plot_histograms and columns:
        for col in columns:
            plt.figure()  # Create a new figure for each histogram
            ax = plt.gca()
            ax.hist(df[col], bins=50)
            figs.append(plt.gcf())

    replaced_df = df.copy()
    if plot_histograms and columns:
        return replaced_df, tuple(figs)  # Return the replaced dataframe and a tuple of histogram figures
    else:
        return replaced_df, None  # Return the replaced dataframe and None for no histogram figures
